<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer 
                                v-if="parameter.length > 0" 
                                :key="loadKey"
                                :viewerId="'viewer_' + loadKey"
                                :parameter="parameter" 
                                :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';

export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            reportPath: null,
            parameter: [],
            clientIds: '',
            LocationId: 0,
            currentReportParams: null,
            loadKey: 0,
            autoRunAttempted: false,
            
            // Store URL parameters
            urlParams: {
                cid: '',
                uid: '',
                did: '',
                sid: '',
                st: '',
                frq: '',
                wdf: '',
                wdt: '',
                pdf: '',
                pdt: '',
                wid: ''
            },
            
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "MultiSelectField",
                            label: this.$t("ClientName"),
                            name: "Clientname",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Client'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.onChangeDropdown,
                                onRemove: this.removeRecord
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("UtilityName"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.GetInvoiceGrouping
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Invoice grouping"),
                            name: "Invoicegrouping",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        },
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Status"),
                            name: "Status",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [{name:'Billed Records', value: "1" }
                                ,{name:'Unbilled Records', value: "2"}]
                            },
                            validationRules: {
                                "required": true
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Work Date From(M/D/YYYY)'),
                            name: "Fromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {
                                format: "M/D/YYYY",
                                options: [],
                                onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Work Date To(M/D/YYYY)'),
                            name: "ToDate",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                                options: [],
                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('State'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Frequency"),
                            name: "Frequency",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [
                                {name:'Annually', value: "annual"}
                                ,{name:'Bi-Weekly', value: "biweek"}
                                ,{name:'Custom Date', value: "custom" }
                                ,{name:'Daily', value: "daily" } 
                                ,{name:'Half yearly', value: "halfyear" }
                                ,{name:'Monthly', value: "month" }
                                ,{name:'Quarterly', value: "quarterly" }  
                               ,{name:'Weekly', value: "week" }]                                
                            },
                            validationRules: {
                                "required": false
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Proccess Date From(M/D/YYYY)'),
                            name: "ProccessFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {
                                format: "M/D/YYYY",
                                options: [],
                                onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Proccess Date To(M/D/YYYY)'),
                            name: "ProccessToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                format: "M/D/YYYY",
                                options: [],
                            }
                        },
                        {
                            astype: "multiSelectField",
                            label: this.$t("Work Code"),
                            name: "Workcode",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ],
            DataLoaded: 0,
        };
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        
        // Parse URL parameters first
        vm.parseUrlParameters();
        
        vm.DataLoaded = 1;
    },
    mounted() {
        // Wait for next tick to ensure DOM is ready
        this.$nextTick(() => {
            this.initializePage();
        });
        window.handleExceededLink = () => {
            this.saveReportRequest();
        };
    },
    beforeDestroy() {
        delete window.handleExceededLink;
    },
    methods: {   
        // Parse URL parameters from query string
        parseUrlParameters() {
            const vm = this;
            const query = vm.$route.query;
            
            // Store all parameters
            vm.urlParams = {
                cid: query.cid || '',
                uid: query.uid || '',
                did: query.did || '',
                sid: query.sid || '',
                st: query.st || '',
                frq: query.frq || '',
                wdf: query.wdf || '',
                wdt: query.wdt || '',
                pdf: query.pdf || '',
                pdt: query.pdt || '',
                wid: query.wid || ''
            };
            
            console.log('URL Parameters loaded:', vm.urlParams);
        },
        
        // Initialize page - load data and set form values
        async initializePage() {
            const vm = this;
            
            // Show loading
            vm.isLoading = true;
            
            try {
                // Step 1: Load all dropdown data
                await Promise.all([
                    vm.GetClient(),
                    vm.GetDDLStateList(),
                    vm.GetWorkCodeInfo()
                ]);
                
                console.log('All dropdown data loaded');
                
                // Step 2: Wait for form component to be ready
                await vm.waitForFormComponent();
                
                // Step 3: Set form values from URL parameters
                await vm.setFormValuesFromUrl();
                
                console.log('Form values set from URL');
                
                // Step 4: Wait a bit for form to update
                await new Promise(resolve => setTimeout(resolve, 500));
                
                // Step 5: Run the report automatically
                await vm.autoRunReport();
                
            } catch (error) {
                console.error('Error initializing page:', error);
                vm.ShowAlert("Error loading form: " + error.message, "failure", true, vm.$t("Alert"));
            } finally {
                vm.isLoading = false;
            }
        },
        
        // Wait for form component to be ready
        waitForFormComponent() {
            return new Promise((resolve, reject) => {
                const maxAttempts = 20;
                let attempts = 0;
                
                const checkForm = () => {
                    attempts++;
                    if (this.$refs.BarcodeReport) {
                        console.log('Form component found on attempt', attempts);
                        resolve();
                    } else if (attempts >= maxAttempts) {
                        reject(new Error('Form component not found after ' + maxAttempts + ' attempts'));
                    } else {
                        setTimeout(checkForm, 100);
                    }
                };
                
                checkForm();
            });
        },
        
        // Set form values from URL parameters
        async setFormValuesFromUrl() {
            const vm = this;
            
            // Helper function to convert date format from YYYY-MM-DD to MM/DD/YYYY
            const convertDateFormat = (dateStr) => {
                if (!dateStr || dateStr === '0001-01-01' || dateStr === '') return '';
                try {
                    return moment(dateStr, 'YYYY-MM-DD').format('MM/DD/YYYY');
                } catch (e) {
                    console.error('Error converting date:', dateStr, e);
                    return '';
                }
            };
            
            // 1. Set Client (cid) - multi-select
            if (vm.urlParams.cid && vm.urlParams.cid !== '') {
                const clientIds = vm.urlParams.cid.split(',').filter(id => id.trim() !== '');
                const selectedClients = [];
                
                // Find client objects from options
                clientIds.forEach(clientId => {
                    const clientOption = vm.FormSchema[0].Data[0].config.options.find(opt => 
                        opt.value.toString() === clientId.toString().trim()
                    );
                    if (clientOption) {
                        selectedClients.push(clientOption);
                    } else {
                        console.warn('Client not found in options:', clientId);
                    }
                });
                
                if (selectedClients.length > 0) {
                    vm.FormSchema[0].Data[0].value = selectedClients;
                    vm.clientIds = selectedClients.map(item => item.value).join(",");
                    
                    // Load utility options based on client
                    await vm.loadUtilityFromUrl();
                }
            }
            
            // 2. Set Status (sid) - single select
            if (vm.urlParams.sid && vm.urlParams.sid !== '') {
                vm.FormSchema[1].Data[0].value = vm.urlParams.sid.toString();
            }
            
            // 3. Set Work Date From (wdf)
            if (vm.urlParams.wdf && vm.urlParams.wdf !== '') {
                const formattedDate = convertDateFormat(vm.urlParams.wdf);
                if (formattedDate) {
                    vm.FormSchema[1].Data[1].value = formattedDate;
                }
            }
            
            // 4. Set Work Date To (wdt)
            if (vm.urlParams.wdt && vm.urlParams.wdt !== '') {
                const formattedDate = convertDateFormat(vm.urlParams.wdt);
                if (formattedDate) {
                    vm.FormSchema[1].Data[2].value = formattedDate;
                }
            }
            
            // 5. Set State (st)
            if (vm.urlParams.st && vm.urlParams.st !== '') {
                const stateOption = vm.FormSchema[1].Data[3].config.options.find(opt => 
                    opt.value.toString() === vm.urlParams.st.toString()
                );
                if (stateOption) {
                    vm.FormSchema[1].Data[3].value = stateOption.value;
                }
            }
            
            // 6. Set Frequency (frq)
            if (vm.urlParams.frq && vm.urlParams.frq !== '') {
                vm.FormSchema[2].Data[0].value = vm.urlParams.frq;
            }
            
            // 7. Set Process Date From (pdf)
            if (vm.urlParams.pdf && vm.urlParams.pdf !== '' && vm.urlParams.pdf !== '0001-01-01') {
                const formattedDate = convertDateFormat(vm.urlParams.pdf);
                if (formattedDate) {
                    vm.FormSchema[2].Data[1].value = formattedDate;
                }
            }
            
            // 8. Set Process Date To (pdt)
            if (vm.urlParams.pdt && vm.urlParams.pdt !== '' && vm.urlParams.pdt !== '0001-01-01') {
                const formattedDate = convertDateFormat(vm.urlParams.pdt);
                if (formattedDate) {
                    vm.FormSchema[2].Data[2].value = formattedDate;
                }
            }
            
            // 9. Set Work Code (wid) - multi-select
            if (vm.urlParams.wid && vm.urlParams.wid !== '') {
                const workCodeIds = vm.urlParams.wid.split(',').filter(id => id.trim() !== '');
                const selectedWorkCodes = [];
                
                // Find work code objects from options
                workCodeIds.forEach(workCodeId => {
                    const workCodeOption = vm.FormSchema[2].Data[3].config.options.find(opt => 
                        opt.value.toString() === workCodeId.toString().trim()
                    );
                    if (workCodeOption) {
                        selectedWorkCodes.push(workCodeOption);
                    }
                });
                
                if (selectedWorkCodes.length > 0) {
                    vm.FormSchema[2].Data[3].value = selectedWorkCodes;
                }
            }
            
            // Update the form to reflect changes
            if (vm.$refs.BarcodeReport) {
                await vm.$nextTick();
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        
        // Load utility options based on URL parameter (uid)
        async loadUtilityFromUrl() {
            const vm = this;
            
            if (!vm.clientIds) return;
            
            // Clear existing utility options
            vm.FormSchema[0].Data[1].config.options = [];
            vm.FormSchema[0].Data[1].value = '';
            
            // Load utility options
            var params = {clientId: '', configid: 0, Reqfrom: "BILLED_UNBILLED_REPORT", clientIds: vm.clientIds};            
            var queryString = Object.keys(params).map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`).join('&');
            
            await DataServices.GetUtilityByClient(queryString).then(function (response) {           
                response.data.forEach(item => {
                    const obj = {
                        label: item.UTILITY_NAME,
                        name: item.UTILITY_NAME,
                        value: item.UTILITY_ID,
                        parentId: vm.clientIds
                    }
                    vm.FormSchema[0].Data[1].config.options.push(obj);                                             
                });
                
                // Now set utility value from URL if provided
                if (vm.urlParams.uid && vm.urlParams.uid !== '') {
                    const utilityIds = vm.urlParams.uid.split(',').filter(id => id.trim() !== '');
                    const selectedUtilities = [];
                    
                    utilityIds.forEach(utilityId => {
                        const utilityOption = vm.FormSchema[0].Data[1].config.options.find(opt => 
                            opt.value.toString() === utilityId.toString().trim()
                        );
                        if (utilityOption) {
                            selectedUtilities.push(utilityOption);
                        }
                    });
                    
                    if (selectedUtilities.length > 0) {
                        vm.FormSchema[0].Data[1].value = selectedUtilities;
                        
                        // Load invoice grouping based on utility
                        vm.loadInvoiceGroupingFromUrl();
                    }
                }
                
                // Update form
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        
        // Load invoice grouping based on URL parameter (did)
        async loadInvoiceGroupingFromUrl() {
            const vm = this;
            
            if (!vm.clientIds) return;
            
            // Get utility values
            const utilityValues = vm.FormSchema[0].Data[1].value;
            const utilityIds = Array.isArray(utilityValues) 
                ? utilityValues.map(item => item.value).join(",") 
                : '';
            
            // Load invoice grouping options
            var url = `ClientId=${vm.clientIds}&UtilityIds=${utilityIds}`;
            await DataServices.GetInvoiceGrouping(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    vm.FormSchema[0].Data[2].config.options = [];
                    
                    UtilityData.forEach(element => {
                        var Obj = {
                            label: element.NOTE,
                            name: element.NOTE,
                            value: element.ID
                        }
                        vm.FormSchema[0].Data[2].config.options.push(Obj);
                    });
                    
                    // Now set invoice grouping value from URL if provided
                    if (vm.urlParams.did && vm.urlParams.did !== '') {
                        const divisionIds = vm.urlParams.did.split(',').filter(id => id.trim() !== '');
                        const selectedDivisions = [];
                        
                        divisionIds.forEach(divisionId => {
                            const divisionOption = vm.FormSchema[0].Data[2].config.options.find(opt => 
                                opt.value.toString() === divisionId.toString().trim()
                            );
                            if (divisionOption) {
                                selectedDivisions.push(divisionOption);
                            }
                        });
                        
                        if (selectedDivisions.length > 0) {
                            vm.FormSchema[0].Data[2].value = selectedDivisions;
                        }
                    }
                    
                    // Update form
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            });
        },
        
        // Get current form data from FormSchema
        getCurrentFormData() {
            const vm = this;
            const formData = {};
            
            // Extract data from FormSchema
            vm.FormSchema.forEach(section => {
                section.Data.forEach(field => {
                    formData[field.name] = field.value;
                });
            });
            
            return formData;
        },
        
        // Automatically run report after form is populated
        async autoRunReport() {
            const vm = this;
            
            // Prevent multiple auto-run attempts
            if (vm.autoRunAttempted) return;
            vm.autoRunAttempted = true;
            
            console.log('Auto-running report...');
            
            // Wait for form to be fully ready
            await vm.$nextTick();
            
            if (!vm.$refs.BarcodeReport) {
                console.error('Form component not found for auto-run');
                return;
            }
            
            try {
                // Get form data from current FormSchema state
                const formData = vm.getCurrentFormData();
                
                console.log('Form data for auto-run:', formData);
                
                // Check if we have at least required data to run the report
                // Status is required, so check if it's set
                if (!formData || !formData.Status) {
                    console.log('Required data (Status) not available for auto-running report');
                    return;
                }
                
                // Run the report
                await vm.onSubmit(formData);
                
            } catch (error) {
                console.error('Error auto-running report:', error);
            }
        },
        
        setTimerDate:function(x, y, z){
            var vm =this;
            if(y.name == "Fromdate"){                           
                vm.$refs.BarcodeReport.updateProperty("ToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            } 
            if(y.name == "ProccessFromdate"){                           
                vm.$refs.BarcodeReport.updateProperty("ProccessToDate", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            }  
        },     
        async onSubmit(e) {
            var vm = this;
            
            // Handle case where e might be undefined or null
            if (!e) {
                console.error('Form data is empty');
                return;
            }
            
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            
            // Helper function to extract values from form data
            const extractValues = (fieldValue) => {
                if (!fieldValue) return '';
                if (Array.isArray(fieldValue)) {
                    return fieldValue.map(item => item.value).join(",");
                }
                return fieldValue;
            };
            
            let myObj = {
                reportName: "billedunbilledreport",
                ClientIds: extractValues(e.Clientname),
                dateFrom: e.Fromdate ? this.formatDate(e.Fromdate) : null,
                dateTo: e.ToDate ? this.formatDate(e.ToDate) : null,
                ProccessFromDate: e.ProccessFromdate ? this.formatDate(e.ProccessFromdate) : null,
                ProccessToDate: e.ProccessToDate ? this.formatDate(e.ProccessToDate) : null,
                Invoicegrouping: extractValues(e.Invoicegrouping),
                State: e.State,
                Status: e.Status,
                Frequency: e.Frequency,
                UtilityName: extractValues(e.UtilityName),
                Workcode: extractValues(e.Workcode),
            };
            vm.currentReportParams = myObj;

            console.log('Submitting report with data:', myObj);
            
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
                vm.isLoading = false;
                console.log('Report loaded successfully');
            }).catch(function (error) {
                console.error("Error loading report:", error);
                vm.isLoading = false;
            });
        },
        
        // Helper method to format date
        formatDate(value) {
            if (!value) return null;
            try {
                return moment(value).format('MM-DD-YYYY');
            } catch (e) {
                console.error('Error formatting date:', value, e);
                return null;
            }
        },
        
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options=[];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[2].value = '';
            (vm.FormSchema)[2].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.currentReportParams = null;
            vm.loadKey = 0;
            vm.autoRunAttempted = false;
            if (vm.$refs.BarcodeReport && vm.$refs.BarcodeReport.validateForm) {
                vm.$refs.BarcodeReport.validateForm.reset();
            }
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            return new Promise((resolve) => {
                DataServices.GetClient(params).then((response) => {
                    if (response.data.length > 0) {
                        var ClientData = response.data;
                        ClientData.forEach(element => {
                            var Obj = {
                                label: element.CHILD_NAME,
                                name: element.CHILD_NAME,
                                value: element.CHILD_USER_ID
                            }
                            vm.FormSchema[0].Data[0].config.options.push(Obj);
                        });
                        console.log('Client data loaded:', vm.FormSchema[0].Data[0].config.options.length, 'clients');
                        resolve();
                    } else {
                        console.warn('No client data received');
                        resolve();
                    }
                }).catch(error => {
                    console.error('Error loading clients:', error);
                    resolve();
                });
            });
        },
        removeRecord(event, field, meta)  {
          this.onChangeDropdown('Remove',meta,event);
        },
        async onChangeDropdown(e, field, evt) { 
            var vm = this;
            vm.isLoading = true;

            vm.clientIds = '';
            if (Array.isArray(field.value) && field.value.length > 0) {
                const combinedValue = field.value.map(item => item.value).join(",");
                vm.clientIds = combinedValue;
            }

            if (evt.value !== null && evt.value !== "" && e!=='Remove') {
                vm.clientIds = evt.value;
            }

            if (e === 'Remove') {
                if (vm.clientIds) {
                    const clientIds = vm.clientIds.split(',');
                    const filteredclientIds = clientIds.filter(id => id !== evt.value.toString());
                    vm.clientIds = filteredclientIds.join(',');

                    let options = vm.FormSchema[0].Data[1].config.options;
                    let values = vm.FormSchema[0].Data[1].value;

                    let ids = vm.clientIds.split(',');

                    vm.FormSchema[0].Data[1].value = values.filter(v =>
                        options.some(o => ids.includes(o.parentId.toString()) && o.value == v.value)
                    );
                    vm.FormSchema[0].Data[1].config.options = [];
                    vm.FormSchema[0].Data[2].config.options = [];
                    vm.FormSchema[0].Data[2].value = '';
                    vm.GetInvoiceGrouping(vm.clientIds);
                }
            }

            var params = {clientId: '', configid: 0, Reqfrom: "BILLED_UNBILLED_REPORT", clientIds: vm.clientIds};            
            var queryString = Object.keys(params).map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`).join('&');

            await DataServices.GetUtilityByClient(queryString).then(function (response) {           
                response.data.forEach(item => {
                    const obj = {
                        name: item.UTILITY_NAME,
                        value: item.UTILITY_ID,
                        parentId: vm.clientIds
                    }
                    vm.FormSchema[0].Data[1].config.options.push(obj);                                             
                });
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
                vm.isLoading = false;
            });           
        },
        GetInvoiceGrouping: async function (x, y, z) {
            var vm = this;
            var url = `ClientId=${vm.clientIds}&UtilityIds=`;
            await DataServices.GetInvoiceGrouping(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.NOTE,
                            value: element.ID
                        }
                        vm.FormSchema[0].Data[2].config.options.push(Obj);
                    });
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            });
        },
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            return new Promise((resolve) => {
                DataServices.GetDDLStateList(params).then((response) => {
                    if (response.data.length > 0) {
                        var StateData = response.data;
                        StateData.forEach(item => {
                            vm.FormSchema[1].Data[3].config.options.push({
                                name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                                value: item.ISO_CODE_3
                            });
                        });
                        console.log('State data loaded:', vm.FormSchema[1].Data[3].config.options.length, 'states');
                        resolve();
                    } else {
                        console.warn('No state data received');
                        resolve();
                    }
                }).catch(error => {
                    console.error('Error loading states:', error);
                    resolve();
                });
            });
        },        
        GetWorkCodeInfo: async function () {
            var vm = this;
            return new Promise((resolve) => {
                DataServices.GetWorkCodeInfo().then((response) => {
                    if (response.data.length > 0) {
                        var WorkCodeData = response.data;
                        WorkCodeData.forEach(item => {
                            vm.FormSchema[2].Data[3].config.options.push({
                                name: item.work_code,
                                value: item.work_code_id
                            });
                        });
                        console.log('Work code data loaded:', vm.FormSchema[2].Data[3].config.options.length, 'work codes');
                        resolve();
                    } else {
                        console.warn('No work code data received');
                        resolve();
                    }
                }).catch(error => {
                    console.error('Error loading work codes:', error);
                    resolve();
                });
            });
        },
        async saveReportRequest() {
            var vm = this;
            vm.isLoading = true;
            try {
                if (!vm.currentReportParams) {
                    console.error('No report parameters available. Please generate a report first.');
                    return;
                }

                const params = {
                    reportName: vm.currentReportParams.reportName || 'billedunbilledreport',
                    hdnClientId: vm.currentReportParams.ClientIds || '',
                    startDate: vm.currentReportParams.dateFrom || '',
                    endDate: vm.currentReportParams.dateTo || '',
                    DivisionInvoiceFrequency: vm.currentReportParams.Frequency || '',
                    hdnStatusId: vm.currentReportParams.Status || '',
                    hdnState: vm.currentReportParams.State || '',
                    UtilityNames: vm.currentReportParams.UtilityName || '',
                    DivisionNames: vm.currentReportParams.Invoicegrouping || '',
                    ProcessFromDate: vm.currentReportParams.ProccessFromDate || '',
                    ProcessToDate: vm.currentReportParams.ProccessToDate || '',
                    Workcode: vm.currentReportParams.Workcode || ''
                };

                console.log('Saving report request with params:', params);

                let response = await DataServices.SaveReportRequest(params);
                if (response.data && response.data.result === 'success') {
                    vm.ShowAlert("Request submitted successfully", "success", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert("We couldn't submit your request. Please try again.", "failure", true, vm.$t("Alert"));
                }
            } catch (error) {
                console.error('Error saving report request:', error);
            } finally {
                vm.isLoading = false;
            }
        }
    }
};
</script>